function fibonacci(n) {
  if (n < 0) throw new Error('Negative index not allowed');
  if (n === 0) return 0;
  if (n === 1) return 1;
  let prev = 0, curr = 1;
  for (let i = 2; i <= n; i++) {
    const next = prev + curr;
    prev = curr;
    curr = next;
  }
  return curr;
}

// Explanation:
// The function initializes the first two Fibonacci numbers (0 and 1). It then iterates from 2 to n,
// computing each next value as the sum of the two preceding values. The loop performs a constant
// amount of work per iteration, so the total number of operations grows linearly with n.
// Therefore, the time complexity is O(n). The space complexity is O(1) because only a few
// variables are stored regardless of n.

def fibonacci(n):
    """Return a list of Fibonacci numbers up to n (inclusive)."""
    if n < 0:
        return []
    fibs = [0]
    if n == 0:
        return fibs
    fibs.append(1)
    while fibs[-1] + fibs[-2] <= n:
        fibs.append(fibs[-1] + fibs[-2])
    return fibs
